define('taoQtiItem/qtiCommonRenderer/renderers/interactions/pci/instanciator',['qtiCustomInteractionContext'], function (qtiCustomInteractionContext) {
  'use strict';

  qtiCustomInteractionContext = qtiCustomInteractionContext && Object.prototype.hasOwnProperty.call(qtiCustomInteractionContext, 'default') ? qtiCustomInteractionContext['default'] : qtiCustomInteractionContext;
  var instanciator = {
    getPci(interaction) {
      var pciTypeIdentifier;
      var pci = interaction.data('pci');
      if (!pci) {
        pciTypeIdentifier = interaction.typeIdentifier;
        pci = qtiCustomInteractionContext.createPciInstance(pciTypeIdentifier);
        if (pci) {
          interaction.data('pci', pci);
          pci._taoCustomInteraction = interaction;
        } else {
          throw new Error('no custom interaction hook found for the type ' + pciTypeIdentifier);
        }
      }
      return pci;
    },
    setPci(interaction, instance) {
      interaction.data('pci', instance);
    }
  };
  return instanciator;
});
