define('taoQtiItem/qtiItem/helper/itemScore',[],function () {
  'use strict';
  var itemScore = responseIdentifiers => {
    var outcomeExpressions = responseIdentifiers.map(outcomeIdentifier => ({
      qtiClass: 'variable',
      attributes: {
        identifier: "SCORE_".concat(outcomeIdentifier)
      }
    }));
    return {
      qtiClass: 'setOutcomeValue',
      attributes: {
        identifier: 'SCORE'
      },
      expression: {
        qtiClass: 'sum',
        expressions: outcomeExpressions
      }
    };
  };
  return itemScore;
});
